args.script:
const input = document.getElementById('input');
const output = document.getElementById('output');
const status = document.getElementById('status');

// Load selected text
const selectedText = formData.selectedText || '';
input.value = selectedText;

// Tool handlers
const tools = {
  uppercase: (t) => t.toUpperCase(),
  lowercase: (t) => t.toLowerCase(),
  titlecase: (t) => t.replace(/\w\S*/g, txt => txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase()),
  reverse: (t) => t.split('').reverse().join(''),
  trim: (t) => t.trim().replace(/\s+/g, ' '),
  slug: (t) => t.toLowerCase().trim().replace(/[^\w\s-]/g, '').replace(/\s+/g, '-'),
  count: (t) => `Characters: ${t.length}\nWords: ${t.split(/\s+/).filter(Boolean).length}\nLines: ${t.split('\n').length}`,
  json: (t) => { try { return JSON.stringify(JSON.parse(t), null, 2); } catch { return 'Invalid JSON'; } },
};

// AI tools
async function aiTool(prompt, text) {
  status.textContent = 'Processing with AI...';
  try {
    const result = await stuard.callTool('ai_inference', {
      prompt: `${prompt}:\n\n${text}`,
      maxTokens: 500
    });
    if (result.ok) {
      return result.text || result.response || 'No response';
    }
    return 'Error: ' + (result.error || 'AI request failed');
  } catch (e) {
    return 'Error: ' + e.message;
  } finally {
    status.textContent = 'Ready';
  }
}

// Handle tool clicks
document.querySelectorAll('[data-tool]').forEach(btn => {
  btn.addEventListener('click', async () => {
    const tool = btn.dataset.tool;
    const text = input.value;

    if (!text.trim()) {
      output.value = 'No text to process';
      return;
    }

    if (tool === 'ai_rewrite') {
      output.value = await aiTool('Rewrite the following text to be clearer and more professional', text);
    } else if (tool === 'ai_summarize') {
      output.value = await aiTool('Summarize the following text in 2-3 sentences', text);
    } else if (tools[tool]) {
      output.value = tools[tool](text);
    }
  });
});

// Copy result
document.getElementById('copy-result').addEventListener('click', async () => {
  if (output.value) {
    await stuard.copyToClipboard(output.value);
    status.textContent = 'Copied!';
    setTimeout(() => status.textContent = 'Ready', 1500);
  }
});

// Replace and close
document.getElementById('replace').addEventListener('click', async () => {
  if (output.value) {
    await stuard.copyToClipboard(output.value);
    stuard.close({ action: 'replace', result: output.value });
  }
});

// Escape to close
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') stuard.close();
});
